/**
 * Fetches live status from Stripe (cached 60s in-memory). Pass
`fresh=true` to bypass the cache. Updates the cached
`stripe_onboarding_status` and `stripe_capabilities_json` columns
on the supplier row when the status changes.

 * @summary Live Stripe Connect onboarding status
 */
export const getGetSupplierOnboardingStatusUrl = (
  id: string,
  params?: GetSupplierOnboardingStatusParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/suppliers/${id}/onboarding-status?${stringifiedParams}`
    : `/api/suppliers/${id}/onboarding-status`;
};

export const getSupplierOnboardingStatus = async (
  id: string,
  params?: GetSupplierOnboardingStatusParams,
  options?: RequestInit,
): Promise<SupplierOnboardingStatusResponse> => {
  return customFetch<SupplierOnboardingStatusResponse>(
    getGetSupplierOnboardingStatusUrl(id, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getGetSupplierOnboardingStatusQueryKey = (
  id: string,
  params?: GetSupplierOnboardingStatusParams,
) => {
  return [
    `/api/suppliers/${id}/onboarding-status`,
    ...(params ? [params] : []),
  ] as const;
};

